mapper.sql:
FROM ( SELECT order_id, MAX(vehicle_type) AS vehicle_type, MAX(CASE WHEN sequence = 'ENGINE' THEN part_id END) AS engine, MAX(CASE WHEN sequence = 'DRIVE' THEN part_id END) AS drive, MAX(CASE WHEN sequence = 'TIRE' THEN part_id END) AS tire, MAX(CASE WHEN sequence = 'SEAT' THEN part_id END) AS seat, NULLIF( GROUP_CONCAT( CASE WHEN sequence = 'OPTION' AND part_id IS NOT NULL AND part_id <> 'NULL' THEN part_id ELSE NULL END ORDER BY part_id SEPARATOR ', ' ), '' ) AS `option`, MAX(order_date) AS order_date, MAX(order_status) AS order_status FROM orders GROUP BY order_id ) t WHERE 1 = 1
AND t.vehicle_type = #{vehicleType}
AND t.engine = #{engine}
AND t.drive = #{drive}
AND t.tire = #{tire}
AND t.seat = #{seat}
AND EXISTS ( SELECT 1 FROM orders o2 WHERE o2.order_id = t.order_id AND o2.sequence = 'OPTION' AND o2.part_id = #{optionPartId} )
AND t.`option` IS NULL
